1	import {
2	  type ActorMetadata,
3	  type CurrencyMetadata,
4	  FieldMetadataType,
5	} from 'twenty-shared/types';
6	
7	import { BaseWorkspaceEntity } from 'src/engine/twenty-orm/base.workspace-entity';
8	import { type FieldTypeAndNameMetadata } from 'src/engine/workspace-manager/utils/get-ts-vector-column-expression.util';
9	import { type EntityRelation } from 'src/engine/workspace-manager/workspace-migration/types/entity-relation.interface';
10	import { type AttachmentWorkspaceEntity } from 'src/modules/attachment/standard-objects/attachment.workspace-entity';
11	import { type CompanyWorkspaceEntity } from 'src/modules/company/standard-objects/company.workspace-entity';
12	import { type NoteTargetWorkspaceEntity } from 'src/modules/note/standard-objects/note-target.workspace-entity';
