15	import { type TimelineActivityWorkspaceEntity } from 'src/modules/timeline/standard-objects/timeline-activity.workspace-entity';
16	import { type WorkspaceMemberWorkspaceEntity } from 'src/modules/workspace-member/standard-objects/workspace-member.workspace-entity';
17	import { type DepartmentWorkspaceEntity } from 'src/modules/pop-creations/standard-objects/department.workspace-entity';
18	import { type EmailMessageWorkspaceEntity } from 'src/modules/pop-creations/standard-objects/email-message.workspace-entity';
19	import { type FactoryWorkspaceEntity } from 'src/modules/pop-creations/standard-objects/factory.workspace-entity';
20	import { type LicensorApprovalThreadWorkspaceEntity } from 'src/modules/pop-creations/standard-objects/licensor-approval-thread.workspace-entity';
21	import { type MeetingNoteWorkspaceEntity } from 'src/modules/pop-creations/standard-objects/meeting-note.workspace-entity';
22	
23	const NAME_FIELD_NAME = 'name';
24	
25	export const SEARCH_FIELDS_FOR_OPPORTUNITY: FieldTypeAndNameMetadata[] = [
26	  { name: NAME_FIELD_NAME, type: FieldMetadataType.TEXT },
27	];
28	
29	export class OpportunityWorkspaceEntity extends BaseWorkspaceEntity {
30	  name: string;
31	  amount: CurrencyMetadata | null;
32	  closeDate: Date | null;
33	  stage: string;
34	  position: number;
35	  createdBy: ActorMetadata;
36	  updatedBy: ActorMetadata;
37	  pointOfContact: EntityRelation<PersonWorkspaceEntity> | null;
38	  pointOfContactId: string | null;
39	  company: EntityRelation<CompanyWorkspaceEntity> | null;
40	  companyId: string | null;
41	  taskTargets: EntityRelation<TaskTargetWorkspaceEntity[]>;
42	  noteTargets: EntityRelation<NoteTargetWorkspaceEntity[]>;
