26	import { type OpportunityWorkspaceEntity } from 'src/modules/opportunity/standard-objects/opportunity.workspace-entity';
27	
28	// ─── Constants ─────────────────────────────────────────────────────────────
29	
30	export const CLICKUP_SYNC_CRON_PATTERN = '0 7 * * *';
31	
32	const CLICKUP_API_BASE = 'https://api.clickup.com/api/v2';
33	
34	const LICENSED_LIST_IDS = [
35	  '13194624',
36	  '901104141567',
37	  '901103451229',
38	  '901103451267',
39	  '901103451188',
40	];
41	
42	const NON_LICENSED_LIST_IDS = ['15061776', '901109204835'];
43	
44	const ALL_LIST_IDS = [...LICENSED_LIST_IDS, ...NON_LICENSED_LIST_IDS];
45	
46	// ─── Job ───────────────────────────────────────────────────────────────────
47	
48	@Processor(MessageQueue.cronQueue)
49	export class ClickUpSyncCronJob {
50	  private readonly logger = new Logger(ClickUpSyncCronJob.name);
51	
52	  constructor(
53	    @InjectRepository(WorkspaceEntity)
54	    private readonly workspaceRepository: Repository<WorkspaceEntity>,
55	    private readonly globalWorkspaceOrmManager: GlobalWorkspaceOrmManager,
56	    private readonly exceptionHandlerService: ExceptionHandlerService,
57	  ) {}
58	
59	  @Process(ClickUpSyncCronJob.name)
60	  @SentryCronMonitor(ClickUpSyncCronJob.name, CLICKUP_SYNC_CRON_PATTERN)
61	  async handle(): Promise<void> {
62	    const clickupToken = process.env.CLICKUP_API_TOKEN;
63	
64	    if (!clickupToken) {
65	      this.logger.warn('Missing CLICKUP_API_TOKEN. Skipping ClickUp sync.');
66	
67	      return;
68	    }
69	
70	    const activeWorkspaces = await this.workspaceRepository.find({
71	      where: { activationStatus: WorkspaceActivationStatus.ACTIVE },
72	    });
73	
74	    for (const workspace of activeWorkspaces) {
75	      try {
76	        await this.processWorkspace(workspace.id, clickupToken);
77	      } catch (error) {
78	        this.exceptionHandlerService.captureExceptions([error], {
79	          workspace: { id: workspace.id },
80	        });
81	      }
82	    }
83	  }
84	
85	  // ── Private helpers ────────────────────────────────────────────────────
86	
87	  private async processWorkspace(
88	    workspaceId: string,
89	    clickupToken: string,
90	  ): Promise<void> {
91	    const authContext = buildSystemAuthContext(workspaceId);
92	
93	    await this.globalWorkspaceOrmManager.executeInWorkspaceContext(async () => {
94	      const opportunityRepo =
95	        await this.globalWorkspaceOrmManager.getRepository<OpportunityWorkspaceEntity>(
96	          workspaceId,
97	          'opportunity',
98	          { shouldBypassPermissionChecks: true },
99	        );
100	
101	      // ── Part 1: Update status for programs with existing clickupTaskId ──
102	      await this.syncExistingTasks(workspaceId, opportunityRepo, clickupToken);
103	
104	      // ── Part 2: Auto-link programs with PO number but no clickupTaskId ──
105	      await this.autoLinkByPoNumber(workspaceId, opportunityRepo, clickupToken);
106	    }, authContext);
107	  }
108	
109	  private async syncExistingTasks(
110	    workspaceId: string,
111	    opportunityRepo: any,
112	    clickupToken: string,
113	  ): Promise<void> {
114	    const programs = await opportunityRepo.find({
115	      where: {
116	        clickupTaskId: Not(IsNull()),
117	      },
118	    });
119	
120	    let updated = 0;
121	    let errors = 0;
122	
123	    for (const program of programs) {
124	      try {
125	        const taskId = (program as any).clickupTaskId;
126	
127	        if (!taskId) continue;
128	
129	        const task = await this.fetchClickUpTask(taskId, clickupToken);
130	
131	        if (!task) continue;
132	
133	        const newStatus = task.status?.status ?? null;
134	        const currentStatus = (program as any).clickupStatus;
135	
136	        if (newStatus && newStatus !== currentStatus) {
137	          await opportunityRepo.update(program.id, {
138	            clickupStatus: newStatus,
139	          } as any);
140	          updated++;
141	        }
142	      } catch (taskError) {
143	        errors++;
144	        this.logger.error(
145	          `[${workspaceId}] Failed to sync ClickUp task for program ${program.id}: ${taskError}`,
146	        );
147	      }
148	    }
149	
150	    this.logger.log(
151	      `[${workspaceId}] ClickUp status sync: ${programs.length} checked, ${updated} updated, ${errors} errors`,
152	    );
153	  }
154	
155	  private async autoLinkByPoNumber(
156	    workspaceId: string,
157	    opportunityRepo: any,
158	    clickupToken: string,
159	  ): Promise<void> {
160	    const unlinkedPrograms = await opportunityRepo
161	      .createQueryBuilder('opp')
162	      .where(`opp."productionPoNumber" IS NOT NULL`)
163	      .andWhere(`opp."productionPoNumber" != ''`)
164	      .andWhere(`opp."clickupTaskId" IS NULL`)
165	      .getMany();
166	
167	    if (unlinkedPrograms.length === 0) {
168	      return;
169	    }
170	
171	    // Build a map of PO numbers to search for
172	    const poToProgramMap = new Map<string, any>();
173	
174	    for (const prog of unlinkedPrograms) {
175	      const po = (prog as any).productionPoNumber?.trim();
176	
177	      if (po) {
178	        poToProgramMap.set(po.toUpperCase(), prog);
179	      }
180	    }
181	
182	    let linked = 0;
183	
184	    // Search each ClickUp list for tasks with matching SAS-PO custom field
185	    for (const listId of ALL_LIST_IDS) {
186	      try {
187	        const tasks = await this.fetchClickUpListTasks(listId, clickupToken);
188	
189	        for (const task of tasks) {
190	          const sasPo = this.extractCustomFieldValue(task, 'SAS-PO');
191	
192	          if (!sasPo) continue;
193	
194	          const program = poToProgramMap.get(sasPo.toUpperCase());
195	
196	          if (program) {
197	            await opportunityRepo.update(program.id, {
198	              clickupTaskId: task.id,
199	              clickupStatus: task.status?.status ?? null,
200	            } as any);
201	
202	            poToProgramMap.delete(sasPo.toUpperCase());
203	            linked++;
204	          }
205	        }
206	      } catch (listError) {
207	        this.logger.error(
208	          `[${workspaceId}] Failed to search ClickUp list ${listId}: ${listError}`,
209	        );
210	      }
211	
212	      // Stop early if all POs have been matched
213	      if (poToProgramMap.size === 0) break;
214	    }
215	
216	    this.logger.log(
217	      `[${workspaceId}] ClickUp auto-link: ${unlinkedPrograms.length} unlinked programs, ${linked} newly linked`,
218	    );
219	  }
220	
221	  private async fetchClickUpTask(
222	    taskId: string,
223	    token: string,
224	  ): Promise<any | null> {
225	    const response = await fetch(`${CLICKUP_API_BASE}/task/${taskId}`, {
226	      method: 'GET',
227	      headers: {
228	        Authorization: token,
229	        'Content-Type': 'application/json',
230	      },
231	    });
232	
233	    if (!response.ok) {
234	      if (response.status === 404) {
235	        this.logger.warn(`ClickUp task ${taskId} not found (404)`);
236	
237	        return null;
238	      }
239	
240	      throw new Error(
241	        `ClickUp API error: ${response.status} ${await response.text()}`,
242	      );
243	    }
244	
245	    return response.json();
246	  }
247	
248	  private async fetchClickUpListTasks(
249	    listId: string,
250	    token: string,
251	  ): Promise<any[]> {
252	    const response = await fetch(
253	      `${CLICKUP_API_BASE}/list/${listId}/task?page=0&include_closed=true`,
254	      {
255	        method: 'GET',
256	        headers: {
257	          Authorization: token,
258	          'Content-Type': 'application/json',
259	        },
260	      },
261	    );
262	
263	    if (!response.ok) {
264	      throw new Error(
265	        `ClickUp list ${listId} fetch failed: ${response.status} ${await response.text()}`,
266	      );
267	    }
268	
269	    const data = await response.json();
270	
271	    return data.tasks ?? [];
272	  }
273	
274	  private extractCustomFieldValue(task: any, fieldName: string): string | null {
275	    const customFields = task.custom_fields ?? [];
276	
277	    const field = customFields.find(
278	      (f: any) => f.name?.toLowerCase() === fieldName.toLowerCase(),
279	    );
280	
281	    return field?.value ?? null;
282	  }
283	}
